export interface PostListOptions {
  /**
   * 文章列表标题
   */
  title?: string

  /**
   * 是否启用带封面卡片的交错翻转布局。
   *
   * 仅当当前文章卡片最终解析到可用封面图时生效：
   * - 启用后，卡片可按索引交替切换图文左右布局
   * - 当文章无封面图，或所有候选封面均加载失败时，卡片退化为纯文本形态
   * - 纯文本卡片不参与翻转，以避免无媒体场景下产生无意义的视觉反向
   *
   * 无图策略：
   * - 当文章未提供显式封面，且远程/本地候选封面均不可用时，
   *   卡片退化为纯文本布局
   */
  imageReversed?: boolean

  /**
   * 本地或静态封面兜底列表。
   *
   * 使用场景：
   * - 当文章未显式提供 `post.cover` 时，作为全局封面候选池参与解析
   * - 当远程随机封面源不可用、请求失败或未启用时，作为回退来源
   *
   * 解析策略：
   * - 不按数组顺序固定取首项
   * - 主题会基于文章路径等稳定标识进行确定性分配，使同一文章稳定命中同一张候选图
   *
   * 设计建议：
   * - 建议提供尺寸、裁切风格、色调相近的一组图片，以降低多列布局下的视觉噪声
   */
  coverFallback?: string[]

  /**
   * 远程随机封面源列表。
   *
   * 使用场景：
   * - 仅在 `coverRandom` 为 `true` 时参与封面解析
   * - 适合作为运行时随机封面来源，而非稳定静态资源
   *
   * 解析策略：
   * - 主题会基于文章稳定标识选择具体接口地址
   * - 对选中的地址附加稳定种子参数，以降低不同文章命中相同缓存结果的概率
   *
   * 注意事项：
   * - 若接口本身始终返回完全随机内容，则跨刷新的一致性取决于远程服务，不由主题完全保证
   * - 当远程源失败时，主题回退到 `coverFallback`
   */
  coverApiUrls?: string[]

  /**
   * 是否启用远程随机封面策略。
   *
   * 优先级关系：
   * 1. `post.cover`
   * 2. `coverApiUrls`（仅当本项为 `true`）
   * 3. `coverFallback`
   *
   * 关闭时：
   * - 不使用远程随机封面源
   * - 仅消费文章显式封面与本地兜底封面池
   */
  coverRandom?: boolean

  /**
   * 是否显示文章列表的摘要
   */
  showExcerpt?: boolean

  /**
   * 文章列表摘要长度，单位为字符，仅在 showExcerpt 为 true 时生效
   * @default 140
   */
  excerptLength?: number

  /**
   * 文章列表的最大列数上限
   * 实际列数由容器宽度、最小卡片宽度与该上限共同决定
   * @default 1
   */
  maxColumns?: number

  /**
   * 单张卡片的最小可读宽度
   * 支持 number（按 px 处理）或 CSS 长度字符串（如 `18rem` / `320px`）
   * 不支持传入`em`等相对单位，以避免受父级字体大小影响导致的布局不稳定
   * @default '18rem'
   */
  minCardWidth?: number | string
}
